// Configuración de los campos sí/no:
// emoji_si, emoji_no, texto_si, texto_no
const BOOL_CONFIG = {
  v_reniec: { label: "RENIEC", si: ["✅", "VALIDO"], no: ["🪪❌", "NO VALIDO"], vacio: ["❓", "Sin dato"] },
  v_sunat: { label: "SUNAT", si: ["✅", "VALIDO"], no: ["🛃❌", "NO VALIDO"], vacio: ["❓", "Sin dato"] },
  v_suministro: { label: "SUMINISTRO", si: ["✅", "VALIDO"], no: ["📟❌", "NO VALIDO"], vacio: ["❓", "Sin dato"] },
  v_residencial: { label: "SUMINISTRO", si: ["✅", "VALIDO"], no: ["🏭❌", "NO RESIDENCIAL"], vacio: ["❓", "Sin dato"] },
  v_expediente: { label: "EXPEDIENTE", si: ["✅", "VALIDO"], no: ["📄❌", "OBSERVADO"], vacio: ["❓", "Sin dato"] },
  v_cocina: { label: "COCINA", si: ["✅", "VALIDO"], no: ["🍳❌", "NO VALIDO"], vacio: ["❓", "Sin dato"] },
  v_piso: { label: "PISO", si: ["✅", "VALIDO"], no: ["🔲❌", "NO VALIDO"], vacio: ["❓", "Sin dato"] },
  v_vivienda: { label: "VIVIENDA", si: ["✅", "VALIDO"], no: ["🏨❌", "NO PRECARIA"], vacio: ["❓", "Sin dato"] },
};

document.getElementById('counter').textContent =
  Object.keys(CATALOGO).length.toLocaleString('es') + ' registros cargados';

document.getElementById('dniInput').addEventListener('keydown', e => {
  if (e.key === 'Enter') buscar();
});

function buscar() {
  const raw  = document.getElementById('dniInput').value.trim();
  const area = document.getElementById('resultArea');
  if (!raw) { area.innerHTML = ''; return; }

  const d = CATALOGO[raw];

  if (!d) {
    area.innerHTML = `
      <div class="not-found">
        <strong><span class="result-badge no-apto">USUARIO NO ATENDIDO</span></strong>
        No existe ningún registro para el DNI <code>${esc(raw)}</code>.
      </div>`;
    return;
  }

  area.innerHTML = `
    <div class="result-card">

      <div class="result-header">
        <span class="result-dni">VERIFICADO</span>
        ${badgeAptitud(d.estado)}
      </div>

      <!-- Bloque 1: cadenas de texto superiores -->
      <div class="section">
        <div class="section-title">DATOS DE LA SOLICITUD</div>
        ${campo("SOLICITANTE", d.solicitante)}
        ${campo("TIPO DE SOLICITUD",  d.tipo_solicitud)}
        ${campo("TIPO DE SUMINISTRO",  d.tipo_sum)}
        ${campo("SUMINISTRO",  d.suministro)}
        ${campo("FECHA DE ATENCIÓN",  d.fecha_atencion)}
        
      </div>

      <!-- Bloque 2: campos sí/no con emoji -->
      <div class="section">
        <div class="section-title">OBSERVACIONES</div>
        <div class="bool-grid">
          ${boolCampo("v_reniec", d.reniec)}
          ${boolCampo("v_sunat", d.sunat)}
          ${boolCampo("v_suministro", d.v_suministro)}
          ${boolCampo("v_residencial", d.v_residencial)}
          ${boolCampo("v_expediente", d.v_expediente)}
          ${boolCampo("v_cocina", d.v_cocina)}
          ${boolCampo("v_piso", d.v_piso)}
          ${boolCampo("v_vivienda", d.v_vivienda)}
        </div>
      </div>

      <!-- Bloque 3: cadenas de texto inferiores -->
      <div class="section">
        ${campo("EJECUCIÓN", d.ejecucion)}
        ${campo("DETALLES", d.v_detalles)}
        ${campo("OTRAS VALIDACIONES", d.v_otros)}
      </div>

    </div>`;
}

function campo(etiqueta, valor) {
  if (!valor || valor.trim() === '') {
    return `<div class="field">
      <span class="field-label">${etiqueta}</span>
      <span class="field-value empty">————NO————</span>
    </div>`;
  }
  return `<div class="field">
    <span class="field-label">${etiqueta}</span>
    <span class="field-value">${esc(valor)}</span>
  </div>`;
}

function boolCampo(clave, valor) {
  const cfg = BOOL_CONFIG[clave];
  let emoji, texto;
  if      (valor === 'NO') 
    { 
      [emoji, texto] = cfg.no;
      return `<div class="bool-field">
        <span class="bool-label">${cfg.label}</span>
        <span class="bool-value">${emoji}</span>
        <span class="bool-text">${texto}</span>
      </div>`;
    }
  
  else if (valor === 'SI')  {return ""}
}


function badgeAptitud(valor) {
  if (valor == 'ATENDIDO')
    return `<span class="result-badge apto">✔ APROBADO</span>`;
  if (valor == 'OBSERVADO')
    return `<span class="result-badge no-apto">✖ OBSERVADO</span>`;
  return `<span class="result-badge sin-dato">NO ATENDIDO</span>`;
}


function esc(s) {
  return String(s)
    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
    .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
